        PRODUCTION_SERVERS = "prod-server1.example.com prod-server2.example.com"
        DEPLOY_PATH = "/opt/myapp"
        ARTIFACT = "myapp.jar"
    }

    stages {
        stage('Checkout') {
            steps {
                // Example checkout step
                checkout scm
            }
        }

        stage('Build') {
            steps {
                sh "echo 'Building application...'"
                // Insert actual build commands here
            }
        }

        stage('Deploy') {
            steps {
                script {
                    for (server in PRODUCTION_SERVERS.split()) {
                        sh """
